@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_6afb5c8c7fd74997a8b117ea823cbb13.Services.WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Name</label>
        <InputText @bind-Value="Wizard.Name" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText @bind-Value="Wizard.Email" class="form-control" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override void OnInitialized()
    {
        Wizard.CurrentStep = 1;
    }

    private void Next()
    {
        Wizard.CompleteStep(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_6afb5c8c7fd74997a8b117ea823cbb13.Services.WizardState Wizard
@inject NavigationManager Nav
@using sv_6afb5c8c7fd74997a8b117ea823cbb13.Services

<PageTitle>Apply - Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@foreach (var entry in Wizard.JobHistory)
{
    <div class="card mb-2 p-2">
        <strong>@entry.Role</strong> at @entry.Company (@entry.Duration)
    </div>
}

<EditForm Model="newEntry" OnValidSubmit="AddEntry" FormName="experience">
    <div class="mb-3">
        <label class="form-label">Company</label>
        <InputText @bind-Value="newEntry.Company" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Role</label>
        <InputText @bind-Value="newEntry.Role" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Duration</label>
        <InputText @bind-Value="newEntry.Duration" class="form-control" />
    </div>
    <button type="submit" class="btn btn-secondary me-2">+ Add Entry</button>
</EditForm>

<div class="mt-3">
    <button class="btn btn-outline-secondary me-2" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private JobHistoryEntry newEntry = new();

    protected override void OnInitialized()
    {
        Wizard.CurrentStep = 2;
    }

    private void AddEntry()
    {
        Wizard.JobHistory.Add(newEntry);
        newEntry = new();
    }

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.CompleteStep(2);
        Nav.NavigateTo("/apply/references");
    }
}

